query:
-- Animal counts
SELECT isActive, COUNT(*) as count FROM animals WHERE deletedAt IS NULL GROUP BY isActive;

-- Expense total
SELECT COUNT(*) as records, SUM(amount) as total FROM expenses WHERE deletedAt IS NULL;

-- Ration plans per category
SELECT ac.name as category, COUNT(*) as plans, SUM(rp.qtyPerHeadPerDay) as total_daily_kg
FROM ration_plans rp
JOIN animal_categories ac ON ac.id = rp.categoryId
WHERE rp.isActive = 1
GROUP BY ac.name ORDER BY ac.name;

-- Sales
SELECT a.animalId, s.salePrice, s.saleDate FROM sales s JOIN animals a ON a.id = s.animalId;

